// ─── Step 1: Parse incoming payload ───────────────────────────────────────
// Supports two modes:
//   A) file_base64 + file_type='docx'  → parse the .docx into blocks
//   B) text (plain string)              → treat whole text as one block

const body = $input.first().json.body;

if (!body) {
  throw new Error('Empty request body');
}

const mode = body.mode || 'gentle';

if (body.text) {
  // ── TEXT MODE ────────────────────────────────────────────────
  // Split on double newlines or treat each line as a block
  const raw = body.text.trim();
  const paragraphs = raw.split(/\n\n+/).filter(p => p.trim().length > 0);

  const blocks = paragraphs.map((p, i) => ({
    id: `p${i}`,
    type: p.trimStart().startsWith('-') || p.trimStart().startsWith('•') || p.trimStart().match(/^\d+\./) ? 'bullet' : 'paragraph',
    text: p.trim()
  }));

  return [{
    json: {
      input_type: 'text',
      mode,
      blocks
    }
  }];
}

if (body.file_base64 && body.file_type === 'docx') {
  // ── DOCX MODE ────────────────────────────────────────────────
  // Pass through for the next node to parse with mammoth
  return [{
    json: {
      input_type: 'docx',
      mode,
      file_base64: body.file_base64,
      blocks: [] // will be filled by Parse DOCX node
    }
  }];
}

throw new Error('Invalid payload: provide either text or file_base64+file_type=docx');

// ─── Step 2: Parse .docx into blocks (only runs for docx input) ──────────
// Uses mammoth (available in n8n's Node.js environment) to extract
// paragraph and bullet text, leaving tables/images/equations untouched.

const item = $input.first().json;

if (item.input_type !== 'docx') {
  // Not a docx — pass through unchanged
  return [$input.first()];
}

// Decode base64 → Buffer
const mammoth = require('mammoth');
const buffer = Buffer.from(item.file_base64, 'base64');

// Extract raw text with paragraph structure
const result = await mammoth.extractRawText({ buffer });
const rawText = result.value;

// Split into paragraphs (mammoth uses \n between paragraphs)
const lines = rawText.split('\n').filter(l => l.trim().length > 0);

const blocks = lines.map((line, i) => {
  const trimmed = line.trim();
  const isBullet = trimmed.startsWith('•') ||
                   trimmed.startsWith('-') ||
                   trimmed.startsWith('*') ||
                   /^\d+\.\s/.test(trimmed);
  return {
    id: `block_${i}`,
    type: isBullet ? 'bullet' : 'paragraph',
    text: trimmed
  };
});

return [{
  json: {
    ...item,
    blocks
  }
}];

// ─── Step 3: Rewrite each block with Groq (Llama) ────────────────────────
// Calls Groq API for each block. Batches in groups of 5 to avoid timeout.
// The product-level prompt is baked here — users never see or change it.

const item = $input.first().json;
const { blocks, mode } = item;

const GROQ_API_KEY = $env.GROQ_API_KEY;
if (!GROQ_API_KEY) throw new Error('GROQ_API_KEY env variable not set in n8n');

const GROQ_URL = 'https://api.groq.com/openai/v1/chat/completions';
const MODEL = 'llama3-8b-8192'; // fast, free on Groq

const modeInstructions = mode === 'aggressive'
  ? `Apply ALL of the following heavily:
   - Substantially restructure sentences and paragraph order.
   - Break complex sentences into several short punchy ones, and occasionally merge short ones.
   - Add informal transitions freely: "In practice," "Anyway," "For example," "In my experience,"
   - Include one deliberate mild typo or spacing irregularity per paragraph.
   - Allow one small natural digression per paragraph (keep same meaning).`
  : `Apply the following lightly:
   - Make moderate sentence-level changes (reorder, split, combine).
   - Add 1–2 informal transitions per block: "In practice," "For example,"
   - One very mild typo or spacing irregularity per every 3–4 paragraphs.
   - No large structural changes.`;

const SYSTEM_PROMPT = `You are an AI-text humanizer. Your job is to rewrite paragraphs and bullet points so they sound like a real human wrote them — not an AI.

Rules you must always follow:
1. Preserve the original meaning and all key facts exactly. Do not add new claims or remove essential information.
2. Only rewrite the given text block. Do not change layout, numbering, or add/remove sections.
3. Rewrite technique — semantic rewrite, NOT word-swap:
   - Change sentence order.
   - Combine short sentences when it sounds natural.
   - Break long sentences when it improves readability.
   - Never just replace words with synonyms.
4. ${modeInstructions}
5. Remove or paraphrase obvious AI-tell phrases like "It is important to note that", "In conclusion", "Firstly", "Furthermore", "In summary", "It is worth mentioning".
6. Output ONLY the rewritten text. No comments, no annotations, no explanations, no quotation marks around the output.`;

// Helper: call Groq for one block
async function rewriteBlock(block) {
  const userMsg = `Rewrite this ${block.type}:\n\n${block.text}`;

  const response = await fetch(GROQ_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${GROQ_API_KEY}`
    },
    body: JSON.stringify({
      model: MODEL,
      messages: [
        { role: 'system', content: SYSTEM_PROMPT },
        { role: 'user', content: userMsg }
      ],
      temperature: mode === 'aggressive' ? 0.9 : 0.7,
      max_tokens: 1024
    })
  });

  if (!response.ok) {
    const err = await response.text();
    console.error('Groq error:', err);
    return block.text; // fallback: return original
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content?.trim() || block.text;
}

// Process blocks in batches of 5
const rewrittenBlocks = [];
const BATCH_SIZE = 5;

for (let i = 0; i < blocks.length; i += BATCH_SIZE) {
  const batch = blocks.slice(i, i + BATCH_SIZE);
  const results = await Promise.all(batch.map(b => rewriteBlock(b)));
  results.forEach((rewritten, j) => {
    rewrittenBlocks.push({
      ...blocks[i + j],
      rewritten_text: rewritten
    });
  });
}

return [{
  json: {
    ...item,
    rewritten_blocks: rewrittenBlocks
  }
}];

// ─── Step 4: Rebuild document / text ─────────────────────────────────────
// For text mode: reassemble paragraphs with double newlines.
// For docx mode: reassemble text then re-pack into a .docx buffer using
//   docxtemplater + pizzip, keeping images/tables/metadata untouched.

const item = $input.first().json;
const { input_type, rewritten_blocks, file_base64 } = item;

if (input_type === 'text') {
  // ── TEXT: just join rewritten paragraphs ────────────────────
  const finalText = rewritten_blocks
    .map(b => b.rewritten_text || b.text)
    .join('\n\n');

  return [{
    json: {
      status: 'success',
      output_type: 'text',
      result: finalText
    }
  }];
}

// ── DOCX: replace paragraph text in the original .docx XML ─────────────
// Strategy: use PizZip to unzip the docx, find w:p (paragraph) nodes in
// word/document.xml, replace their text content with rewritten versions,
// then re-zip and return as base64.

const PizZip = require('pizzip');

// Decode original docx
const originalBuffer = Buffer.from(file_base64, 'base64');
const zip = new PizZip(originalBuffer);

// Get the main document XML
let xml = zip.file('word/document.xml').asText();

// Build a mapping: original text → rewritten text
const replacements = new Map();
rewritten_blocks.forEach(block => {
  if (block.text && block.rewritten_text && block.text !== block.rewritten_text) {
    replacements.set(block.text, block.rewritten_text);
  }
});

// Replace text in XML paragraph nodes
// This works for paragraphs where the full text is in one w:t node.
// For complex paragraphs (split across runs), we fall back gracefully.
for (const [original, rewritten] of replacements.entries()) {
  // Escape original for use in regex
  const escaped = original.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  // Replace within <w:t> tags
  const re = new RegExp(`(<w:t[^>]*>)${escaped}(</w:t>)`, 'g');
  xml = xml.replace(re, `$1${rewritten}$2`);
}

// Write modified XML back into zip
zip.file('word/document.xml', xml);

// Generate new docx buffer and encode as base64
const outputBuffer = zip.generate({ type: 'nodebuffer', compression: 'DEFLATE' });
const outputBase64 = outputBuffer.toString('base64');

return [{
  json: {
    status: 'success',
    output_type: 'docx',
    result: outputBase64
  }
}];
